var maxJump = function(stones) {
    const n = stones.length;
    if (n === 2) return stones[1] - stones[0];
    let best = 0;
    for (let i = 0; i < n - 2; i++) {
        const gap = stones[i + 2] - stones[i];
        if (gap > best) best = gap;
    }
    return best;
};
